import type { Belt } from './belt.js';
import type { BeltHooks } from './hooks.js';

export interface BeltConfig {
  projectName?: string;
  rootDir?: string;
  verbose?: boolean;
  plugins?: Record<string, unknown>;
}

export interface BeltContext {
  cwd: string;
  config: BeltConfig;
  hooks: BeltHooks;
  log: {
    info: (message: string) => void;
    warn: (message: string) => void;
    error: (message: string) => void;
    debug: (message: string) => void;
  };
}

export interface CommandDefinition {
  id: string;
  name: string;
  description: string;
  category?: string;
  shortcut?: string;
  handler: CommandHandler;
}

export type CommandHandler = (ctx: BeltContext, args?: string[]) => Promise<void> | void;

export interface BeltPlugin {
  name: string;
  version?: string;
  apply: (belt: Belt) => void | Promise<void>;
}

export interface CheckResult {
  success: boolean;
  errorCount: number;
  warningCount: number;
  messages: CheckMessage[];
  duration: number;
}

export interface CheckMessage {
  severity: 'error' | 'warning' | 'info';
  message: string;
  file?: string;
  line?: number;
  column?: number;
  ruleId?: string;
}

